testCases.script:
console.log('🚀 开始测试: 文件上传流程');

console.log('⏳ 步骤 1/8: 加载页面...');
await page.waitForLoadState('networkidle');
console.log('✓ 页面加载完成');

console.log('⏳ 步骤 2/8: 等待初始化...');
const dragger = page.locator('.ant-upload-drag');
await dragger.waitFor({ state: 'visible', timeout: 15000 });
console.log('✓ 上传区域已显示，初始化完成');

console.log('⏳ 步骤 3/8: 上传文件...');
const fileInput = page.locator('input[type="file"]');
await fileInput.setInputFiles(__assets + '/test-audio.mp3');
console.log('✓ 文件已选择');

console.log('⏳ 步骤 4/8: 等待文件信息显示...');
const fileNameEl = page.getByText(/test-audio/i);
await fileNameEl.waitFor({ state: 'visible', timeout: 10000 });
console.log('✓ 文件名已显示，进入配置步骤');

console.log('⏳ 步骤 5/8: 检查语言选择器...');
const langSelector = page.locator('[data-id]');
const langCount = await langSelector.count();
console.log('✓ 语言选择器已就绪 (找到 ' + langCount + ' 个选项)');

console.log('⏳ 步骤 6/8: 点击 Transcribe 按钮...');
const transcribeBtn = page.getByRole('button', { name: /transcribe|confirm/i });
await transcribeBtn.click();
console.log('✓ 已点击 Transcribe 按钮');

console.log('⏳ 步骤 7/8: 等待上传进度条...');
const progressBar = page.locator('[class*="progress"]').first();
await progressBar.waitFor({ state: 'visible', timeout: 10000 });
console.log('✓ 上传进度条已显示');

console.log('⏳ 步骤 8/8: 等待结果（成功/限制/错误）...');

const result = await Promise.race([
  page.waitForURL(
    u => u.href.includes('from=official') || u.href.includes('app.notta.ai'),
    { timeout: 90000 }
  ).then(() => 'success'),
  page.locator('[role="dialog"], [class*="dialog"]').waitFor({ state: 'visible', timeout: 90000 }).then(() => 'limit'),
  page.getByText(/error|failed|失败|错误/i).waitFor({ state: 'visible', timeout: 90000 }).then(() => 'error'),
]);

if (result === 'success') {
  console.log('✅ 成功: 已跳转到结果页');
  console.log('结果页 URL:', page.url());
  assert(page.url().includes('from=official'), '应跳转到结果页');
} else if (result === 'limit') {
  console.log('⚠️  达到限制: 显示限制弹窗（IP 限制）');
  const dialogContent = await page.locator('[role="dialog"], [class*="dialog"]').textContent();
  console.log('弹窗内容:', dialogContent.substring(0, 200));
  const signUpBtn = page.getByRole('link', { name: /sign up/i });
  const hasSignUp = await signUpBtn.count() > 0;
  console.log('是否有注册按钮:', hasSignUp);
  assert(hasSignUp, '限制弹窗应有注册按钮');
  console.log('✅ 限制提示正常显示');
} else if (result === 'error') {
  console.log('❌ 出现错误提示');
  const errorText = await page.getByText(/error|failed|失败|错误/i).first().textContent();
  console.log('错误信息:', errorText);
  assert(false, '上传过程中出现错误: ' + errorText);
}

console.log('🚀 开始测试: 粘贴链接流程');

console.log('⏳ 步骤 1/7: 加载页面...');
await page.waitForLoadState('networkidle');
console.log('✓ 页面加载完成');

console.log('⏳ 步骤 2/7: 等待初始化...');
const dragger = page.locator('.ant-upload-drag');
await dragger.waitFor({ state: 'visible', timeout: 15000 });
console.log('✓ 初始化完成');

console.log('⏳ 步骤 3/7: 切换到 Paste a link 标签...');
const pasteLinkTab = page.getByText(/paste a link/i);
await pasteLinkTab.click();
console.log('✓ 已切换到 Paste a link 标签');

console.log('⏳ 步骤 4/7: 输入 YouTube 链接...');
const urlInput = page.locator('input[type="text"]');
await urlInput.waitFor({ state: 'visible', timeout: 5000 });
await urlInput.fill('https://www.youtube.com/watch?v=dQw4w9WgXcQ');
console.log('✓ 已输入 YouTube 链接');

console.log('⏳ 步骤 5/7: 点击 Transcribe 按钮...');
const transcribeBtn = page.getByRole('button', { name: /transcribe|confirm/i });
await transcribeBtn.click();
console.log('✓ 已点击 Transcribe 按钮');

console.log('⏳ 步骤 6/7: 等待加载动画...');
const skeleton = page.locator('[class*="skeleton"], [class*="loading"]').first();
await skeleton.waitFor({ state: 'visible', timeout: 10000 });
console.log('✓ 开始处理链接（显示加载动画）');

console.log('⏳ 步骤 7/7: 等待结果（最长 10 分钟）...');

const result = await Promise.race([
  page.waitForURL(
    u => u.href.includes('from=official') || u.href.includes('app.notta.ai'),
    { timeout: 600000 }
  ).then(() => 'success'),
  page.locator('[role="dialog"], [class*="dialog"]').waitFor({ state: 'visible', timeout: 600000 }).then(() => 'limit'),
  page.getByText(/error|failed|失败|错误/i).waitFor({ state: 'visible', timeout: 600000 }).then(() => 'error'),
]);

if (result === 'success') {
  console.log('✅ 成功: 已跳转到结果页');
  console.log('结果页 URL:', page.url());
  assert(page.url().includes('from=official'), '应跳转到结果页');
} else if (result === 'limit') {
  console.log('⚠️  达到限制: 显示限制弹窗（IP 限制）');
  const dialogContent = await page.locator('[role="dialog"], [class*="dialog"]').textContent();
  console.log('弹窗内容:', dialogContent.substring(0, 200));
  const signUpBtn = page.getByRole('link', { name: /sign up/i });
  const hasSignUp = await signUpBtn.count() > 0;
  console.log('是否有注册按钮:', hasSignUp);
  assert(hasSignUp, '限制弹窗应有注册按钮');
  console.log('✅ 限制提示正常显示');
} else if (result === 'error') {
  console.log('❌ 出现错误提示');
  const errorText = await page.getByText(/error|failed|失败|错误/i).first().textContent();
  console.log('错误信息:', errorText);
  assert(false, '处理链接时出现错误: ' + errorText);
}
